#include <stdio.h>
int maxDepth(char * s) {
    int p = 0, ans = 0;
    for (char *ch = s; *ch; ch++) {
        if (*ch == '(') p++;
        else if (*ch == ')') p--;
        ans = (ans > p) ? ans : p;
    }
    return ans;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    // Method to compute maximum depth of parentheses
    int maxDepth(string s) {
        int p = 0;  
        int ans = 0;
        for (char x : s) {
            // Increase depth on open parenthesis
            if (x == '(') p++;
            // Decrease depth on close parenthesis
            else if (x == ')') p--;
            // Update maximum depth encountered
            ans = max(ans, p);
        }
        return ans;
    }
};

